import collections

def kosaraju(graph):
    all_nodes = set(graph.keys())
    for u in graph:
        for v in graph[u]:
            all_nodes.add(v)

    visited = set()
    finish_stack = []

    def dfs1(u):
        visited.add(u)
        for v in graph.get(u, []):
            if v not in visited:
                dfs1(v)
        finish_stack.append(u)

    for node in all_nodes:
        if node not in visited:
            dfs1(node)

    graph_transpose = collections.defaultdict(list)
    for node in all_nodes:
        graph_transpose[node] = []

    for u in graph:
        for v in graph[u]:
            graph_transpose[v].append(u)

    visited = set()
    sccs = []

    def dfs2(u, current_scc):
        visited.add(u)
        current_scc.append(u)
        for v in graph_transpose.get(u, []):
            if v not in visited:
                dfs2(v, current_scc)

    while finish_stack:
        u = finish_stack.pop()
        if u not in visited:
            current_scc = []
            dfs2(u, current_scc)
            sccs.append(current_scc)

    return sccs
